// ============================================================
// NODE: Validate & Route Incoming Webhook
// ============================================================

const body = $input.first().json.body;

// Handle Meta Webhook Verification
if ($input.first().json.query?.['hub.mode'] === 'subscribe') {
  return [{ json: { type: 'verification', challenge: $input.first().json.query['hub.challenge'] } }];
}

// Validate WhatsApp Message Structure
if (!body?.entry?.[0]?.changes?.[0]?.value?.messages) {
  return [{ json: { type: 'non_message', raw: body } }];
}

const change = body.entry[0].changes[0].value;
const message = change.messages[0];
const contact = change.contacts?.[0];
const wabaId = body.entry[0].id;

return [{
  json: {
    type: 'message',
    waba_id: wabaId,
    phone_number_id: change.metadata.phone_number_id,
    message_id: message.id,
    from_phone: message.from,
    from_name: contact?.profile?.name || 'Unknown',
    message_type: message.type,
    message_text: message.text?.body || '',
    timestamp: message.timestamp
  }
}];

// ============================================================
// NODE: Find client (Supabase row) + Run Guard Checks
// ============================================================

const resp = $input.first().json;
const messageData = $('🔍 Validate & Extract Payload').first().json;

// Supabase REST returns a plain JSON array of matching rows
const rows = Array.isArray(resp) ? resp : (Array.isArray(resp.body) ? resp.body : []);
const client = rows[0] || null;

if (!client) {
  return [{ json: { blocked: true, reason: 'CLIENT_NOT_FOUND', client: null, message_data: messageData } }];
}

if (client.kill_switch) {
  return [{ json: { blocked: true, reason: 'CLIENT_KILL_SWITCH', client, message_data: messageData } }];
}

if (client.maintenance_mode) {
  return [{ json: { blocked: true, reason: 'MAINTENANCE_MODE', client, message_data: messageData } }];
}

if (client.is_active === false) {
  return [{ json: { blocked: true, reason: 'CLIENT_INACTIVE', client, message_data: messageData } }];
}

const now = new Date();
const expiry = client.expiry_date ? new Date(client.expiry_date) : null;
if (expiry && expiry < now) {
  return [{ json: { blocked: true, reason: 'SUBSCRIPTION_EXPIRED', client, message_data: messageData } }];
}

return [{ json: { blocked: false, client, message_data: messageData } }];

// ============================================================
// NODE: Safety Filter — Blocks sensitive topics (Supabase columns are flat)
// ============================================================

const { client, message_data } = $input.first().json;
const text = message_data.message_text.toLowerCase();

if (!client.guardrails_enabled) {
  return [{ json: { safe: true, client, message_data } }];
}

const BLOCKED_PATTERNS = {
  politics: [
    /\b(سياس|انتخاب|حزب|رئيس|برلمان|ثورة|احتجاج|معارضة)\b/i,
    /\b(politique|élection|parti|président|parlement|révolution)\b/i,
    /\b(politic|election|party|president|parliament|revolution)\b/i
  ],
  religion: [
    /\b(دين|إسلام|مسيح|يهود|فتوى|حلال|حرام|كفر|شيعة|سنة)\b/i,
    /\b(religion|islam|chrétien|juif|fatwa|halal|haram)\b/i,
    /\b(religion|islam|christian|jewish|fatwa|halal|haram)\b/i
  ],
  adult_content: [ /\b(sex|nude|xxx|porn|escort)\b/i, /\b(جنس|عاري|بورن|دعارة)\b/i ],
  violence: [
    /\b(bomb|weapon|kill|terrorist|attack)\b/i,
    /\b(قنبلة|سلاح|إرهاب|قتل|هجوم)\b/i
  ]
};

const blockedTopics = client.blocked_topics || ['politics','religion','adult_content','violence'];
let detectedTopic = null;

for (const topic of blockedTopics) {
  if (BLOCKED_PATTERNS[topic]) {
    for (const pattern of BLOCKED_PATTERNS[topic]) {
      if (pattern.test(text)) { detectedTopic = topic; break; }
    }
  }
  if (detectedTopic) break;
}

// Custom blocked words (exact, case-insensitive, per-client)
if (!detectedTopic && Array.isArray(client.custom_blocked_words)) {
  for (const word of client.custom_blocked_words) {
    if (word && text.includes(String(word).toLowerCase())) { detectedTopic = 'custom_blocked_word'; break; }
  }
}

if (detectedTopic) {
  return [{ json: { safe: false, detected_topic: detectedTopic, client, message_data } }];
}

return [{ json: { safe: true, client, message_data } }];

// ============================================================
// NODE: Multi-Lingual Auto-Detection (AR / FR / EN)
// ============================================================

const { client, message_data } = $input.first().json;
const text = message_data.message_text;

if (client.language_mode === 'manual' && client.forced_language) {
  return [{ json: {
    language: client.forced_language,
    detection_method: 'manual_override',
    client, message_data
  }}];
}

const arabicScore  = (text.match(/[\u0600-\u06FF]/g) || []).length;
const frenchScore  = (text.match(/\b(je|tu|il|nous|vous|le|la|les|de|du|est|bonjour|merci|comment|votre)\b/gi) || []).length;
const englishScore = (text.match(/\b(i|you|he|she|we|the|is|are|hello|hi|thank|how|please|help)\b/gi) || []).length;

let language = 'ar';
if (arabicScore > 2) language = 'ar';
else if (frenchScore >= englishScore && frenchScore > 0) language = 'fr';
else if (englishScore > 0) language = 'en';

return [{ json: { language, detection_method: 'auto', client, message_data } }];

// ============================================================
// NODE: Build Arcee Prompt (flat Supabase client object)
// ============================================================

const { client, message_data, language } = $input.first().json;

const langInstructions = {
  ar: 'يجب أن تكون جميع ردودك باللغة العربية. استخدم أسلوباً احترافياً وودوداً.',
  fr: 'Toutes vos réponses doivent être en français, de manière professionnelle.',
  en: 'All your responses must be in English, professional and friendly.'
};

const systemPrompt = `${client.system_prompt || 'أنت مساعد ذكي احترافي.'}

--- قاعدة اللغة الإلزامية ---
${langInstructions[language || 'ar']}

--- إرشادات العلامة التجارية ---
اسم العلامة: ${client.brand_name || client.business_name}
ناقش فقط المواضيع المتعلقة بهذا العمل التجاري.
لا تذكر أبداً المنافسين.
لا تناقش السياسة أو الدين أو المواضيع الحساسة.
إذا سُئلت هل أنت ذكاء اصطناعي: أجب بـ "أنا مساعدك الرقمي" فقط.`;

return [{ json: {
  system_prompt: systemPrompt,
  user_message: message_data.message_text,
  language,
  arcee_model: client.arcee_model || 'arcee-blaze',
  temperature: client.temperature || 0.7,
  max_tokens: client.max_tokens || 1024,
  client,
  message_data
}}];

// ============================================================
// NODE: Extract Arcee Response (flat Supabase client object)
// ============================================================

const arceeResp = $input.first().json;
const promptData = $('📝 Build Arcee Prompt').first().json;

const aiText = arceeResp.choices?.[0]?.message?.content ||
               arceeResp.choices?.[0]?.text ||
               'عذراً، حدث خطأ تقني. يرجى المحاولة مرة أخرى.';

const client = promptData.client;
const messageData = promptData.message_data;

const whatsappPayload = {
  messaging_product: 'whatsapp',
  recipient_type: 'individual',
  to: messageData.from_phone,
  type: 'text',
  text: { body: aiText, preview_url: false }
};

return [{ json: {
  payload: whatsappPayload,
  phone_number_id: client.phone_number_id,
  access_token: client.access_token,
  ai_response: aiText,
  language: promptData.language,
  client,
  message_data: messageData
}}];

// Build the row to insert into Supabase "conversations" table
const formatData = $input.first().json;

return [{ json: {
  client_id: formatData.client.client_id,
  user_phone: formatData.message_data.from_phone,
  user_name: formatData.message_data.from_name || 'Unknown',
  language: formatData.language,
  user_message: formatData.message_data.message_text,
  ai_response: formatData.ai_response,
  is_blocked: false
}}];

// Send blocked/expired message using the client's own fallback text + flat Supabase fields
const blockData = $input.first().json;
const client = blockData.client;
const messageData = blockData.message_data;

const lang = (client && client.language_mode === 'manual' && client.forced_language) ? client.forced_language : 'ar';

const GENERIC = {
  CLIENT_NOT_FOUND:     'عذراً، هذه الخدمة غير متاحة حالياً.',
  CLIENT_KILL_SWITCH:   (client && client.kill_switch_reason) || 'الخدمة موقوفة مؤقتاً. للمساعدة تواصل معنا.',
  SUBSCRIPTION_EXPIRED: 'انتهت صلاحية الاشتراك. يرجى التجديد للاستمرار.',
  MAINTENANCE_MODE:     'الخدمة تحت الصيانة. نعود قريباً.',
  CLIENT_INACTIVE:      'هذا الحساب غير مفعّل حالياً.'
};

let msg;
if (blockData.reason === 'SUBSCRIPTION_EXPIRED' || blockData.reason === 'CLIENT_KILL_SWITCH') {
  // Prefer the client's own configured fallback message when available
  msg = (client && (lang === 'fr' ? client.fallback_fr : lang === 'en' ? client.fallback_en : client.fallback_ar))
        || GENERIC[blockData.reason];
} else {
  msg = GENERIC[blockData.reason] || 'الخدمة غير متاحة.';
}

return [{ json: {
  payload: {
    messaging_product: 'whatsapp',
    to: messageData?.from_phone,
    type: 'text',
    text: { body: msg }
  },
  phone_number_id: client?.phone_number_id,
  access_token: client?.access_token
}}];
